var setSliderFieldValue=function(){"use strict";return function(t=null){(t?[t]:Object.keys(bf_globals)).forEach(t=>{bfSelect(`#form-${t}`)?.querySelectorAll("input[type='range']").forEach(t=>{t.addEventListener("input",e=>{e.target.parentNode.style.setProperty("--bfv-fld-val",JSON.stringify(t.value));const r=(t.value-(t.min||0))/((t.max||100)-(t.min||0))*100;e.target.style.setProperty("--bfv-fill-lower-track",`${r}%`,"important")});const e=window.getComputedStyle(t);t.style.setProperty("--bfv-track-dir","rtl"===e.direction?"to left":"to right")})})}}();
